import{c as e,Q as i,j as t,m as r}from"./chunks/framework.DVkeSyfh.js";const b=JSON.parse('{"title":"Classifiers and Rhythm Lab","description":"","frontmatter":{},"headers":[],"relativePath":"ru/concepts/classifiers-and-rhythm-lab.md","filePath":"ru/concepts/classifiers-and-rhythm-lab.md","lastUpdated":null}'),s={name:"ru/concepts/classifiers-and-rhythm-lab.md"};function o(n,a,l,c,d,p){return i(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="classifiers-and-rhythm-lab" tabindex="-1">Classifiers and Rhythm Lab <a class="header-anchor" href="#classifiers-and-rhythm-lab" aria-label="Permalink to &quot;Classifiers and Rhythm Lab&quot;">​</a></h1><p>Аудитория: Rhythm Lab users и developers<br> Цель: объяснить labels, training artifacts, promotion и scoring<br> Тип: explanation</p><p>Rhythm Lab - labeling and training side classifier workflow. Main app потребляет promoted classifier models и хранит scores.</p><h2 id="two-databases" tabindex="-1">Two databases <a class="header-anchor" href="#two-databases" aria-label="Permalink to &quot;Two databases&quot;">​</a></h2><p>Main library database хранит tracks, metadata, analysis inputs, likes и promoted classifier scores.</p><p>Lab database хранит classifier labels, predictions, training checkpoints и active-learning queues. Lab state по умолчанию живет в <code>tools/rhythm-lab/data/</code>.</p><h2 id="profile-types" tabindex="-1">Profile types <a class="header-anchor" href="#profile-types" aria-label="Permalink to &quot;Profile types&quot;">​</a></h2><ul><li><code>binary</code>: один positive label, один negative label, optional review labels.</li><li><code>multiclass</code>: user-defined class labels; один current class per track для active profile.</li></ul><h2 id="training-inputs" tabindex="-1">Training inputs <a class="header-anchor" href="#training-inputs" aria-label="Permalink to &quot;Training inputs&quot;">​</a></h2><p>Training benchmarks SONARA, MERT, MAEST and combined feature sets. Combined training требует SONARA features plus MERT and MAEST embeddings.</p><h2 id="promotion" tabindex="-1">Promotion <a class="header-anchor" href="#promotion" aria-label="Permalink to &quot;Promotion&quot;">​</a></h2><p>Promotion copies selected combined artifact into <code>models/classifiers/&lt;artifact-prefix&gt;/</code> for main app. Runtime scoring reads promoted manifest and writes scores scoped by classifier key.</p><h2 id="calibration" tabindex="-1">Calibration <a class="header-anchor" href="#calibration" aria-label="Permalink to &quot;Calibration&quot;">​</a></h2><p>Calibration opt-in. <code>--calibrate</code> attempts calibrated training when labels are enough. <code>promote --require-calibration</code> используйте только когда calibrated production behavior intentionally required.</p>',14)])])}const m=e(s,[["render",o]]);export{b as __pageData,m as default};
